var e=[{id:`L2_1`,type:`dialog`,speaker:`MACHINEGAP_COFFIN_NULL_NULL`,text:{KOREA:`후후후......`,JPN:`ふふふ……`,ENG:`*Chuckle*`,TWN:`哈哈哈……`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145010`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MACHINEGAP_COFFIN_NULL_NULL`,text:{KOREA:`나의 취임 이후 이뤄진 첫 작전을 영광스런 승리로 마무리한 것을 축하하네. 제군들.`,JPN:`私の就任後に行われた初作戦で、見事な勝利を収めたな。おめでとう、諸君。`,ENG:`Congratulations on securing this glorious victory on the very first mission under my leadership! Ladies and gentlemen...`,TWN:`祝賀我上任後的第一次作戰，就取得了如此光榮的勝利吧，各位。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145010`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MACHINEGAP_COFFIN_NULL_NULL`,text:{KOREA:`이게 다 나의 뛰어난 영도력의 결과......`,JPN:`これらすべては、私の優れた指導力の賜物……`,ENG:`This is all a result of my outstanding leadership...`,TWN:`這都是在我傑出的領導能力帶領下……`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145010`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`스승님, 통신기 부서졌는데요.`,JPN:`師匠、通信機壊れましたよ。`,ENG:`Master, you broke the radio.`,TWN:`師父，通信器壞掉了喔。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`그래? 손이 미끄러졌나 보군.`,JPN:`そうか？ 手が滑ったかな。`,ENG:`Oh, did I? My hand must have slipped.`,TWN:`是嗎？看來我手滑了呢。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`그라운드 원 중앙 교통 관제실에서 전달 드립니다.`,JPN:`グラウンド・ワン、中央交通管制室からお知らせします。`,ENG:`This is an announcement from Ground One Central Traffic Control Room.`,TWN:`Ground 1，傳達中央交通管制室通知。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`플라티나 특송 여객 소속 수송기가 곧 출발합니다.`,JPN:`プラチナエクスプレスの輸送機がまもなく出発します。`,ENG:`A transport plane from the Platina Express is departing shortly.`,TWN:`普拉提娜客運運輸機即將出發。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`배웅을 위해 나가계신 분들께서는 속히 플랫폼에서 철수해 주시길 바랍니다.`,JPN:`見送りに出ている方々は、速やかにプラットホームから離れてください。`,ENG:`All those standing on the platform must clear the area immediately.`,TWN:`請送別的旅客們盡快從平臺撤離。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`다시 한 번 전달드립니다. 플라티나 특송 여객 수송기가......`,JPN:`繰り返しお知らせします。プラチナ特送旅客の輸送機が……`,ENG:`I repeat. A transport plane from the Platina Express...`,TWN:`重複一次，普拉提娜客運運輸機……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`스승님.`,JPN:`師匠。`,ENG:`Master.`,TWN:`師父。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`왜 또?`,JPN:`なんだ、また。`,ENG:`What now?`,TWN:`又怎麼了？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`아, 잊어 버렸어요.`,JPN:`あ、忘れてしまいました。`,ENG:`Oh, I forgot what I wanted to say.`,TWN:`啊，我忘了我要說什麼了。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`요즘 건망증이 심해서 금방금방 까먹는다니까요. 하하.`,JPN:`最近物忘れがひどくて、すぐ忘れるんですよ、ハハ。`,ENG:`I've been very forgetful these days. Haha.`,TWN:`最近健忘症有點嚴重，一下子就把事情忘掉了呢，哈哈。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`어린 녀석이 벌써부터 싹수가 노랗군.`,JPN:`まだ若いのに、先が思いやられるな。`,ENG:`Are you already getting dementia?`,TWN:`你這小鬼已經不行啦？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`치매검사라도 해 보는 게 어떠냐?`,JPN:`認知症テストでも受けてみたらどうだ？`,ENG:`You should get that checked out.`,TWN:`去檢查一下，看看有沒有得癡呆怎麼樣？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`하하, 생각해 볼게요.`,JPN:`ハハ、考えてみます。`,ENG:`Haha! I'll think about it.`,TWN:`哈哈，我會考慮的。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`그럼 잘 가세요, 스승님.`,JPN:`気を付けてお帰りください、師匠。`,ENG:`Take care, Master.`,TWN:`那就再見囉，師父。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`병원 꼭 들르시고요.`,JPN:`通院もお忘れなくお願いしますね。`,ENG:`Make sure you go to the hospital!`,TWN:`請一定要去醫院喔。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_145021`,slots:{L:null,C:null,R:null}}}];export{e as default};